    knowledge_package: PoliticsKnowledgePointPackage = PoliticsKnowledgePointPackage(
        **json.loads(knowledge_package_str)
    )
    # 增加ID
    for knowledge in knowledge_package.knowledge_points:
        knowledge.outline_id = subject_context.outline.id
        knowledge.document_id = subject_context.document.id
        paragraph_index = int(knowledge.code.split("-")[-2])
        knowledge.content = "\n".join(section_old_lines[indexs[paragraph_index - 1]: indexs[paragraph_index]])
    # 知识点入库
    knowledge_dos = knowledge_convert_bo2do_list(knowledge_package.knowledge_points)
    old_knowledge_dos = db_query.get_all(KnowledgePointDO, outline_id=subject_context.outline.id)
    for old_knowledge_do in old_knowledge_dos:
        db_query.delete(old_knowledge_do)
    db_query.add_all(knowledge_dos)
    # 知识点Embedding
    documents = []
    for knowledge_point in knowledge_package.knowledge_points:
        document = knowledge_point2embedding(knowledge_point)
        documents.append(document)
    old_documents = bge_pipeline.retrieve("", expr=f'outline_id == {subject_context.outline.id}')
    if old_documents:
        old_document_ids = [str(document.metadata.get("id")) for document in old_documents]
        bge_pipeline.del_documents(old_document_ids)
    bge_pipeline.add_documents(documents)

    subject_context.knowledge = knowledge_package.dict()
    return subject_context


