def parse_knowledge_network(subject_context: SubjectContext):
    print("begin parse_knowledge_network")
    knowledge_package: PoliticsKnowledgePointPackage = PoliticsKnowledgePointPackage(**subject_context.knowledge)

    for knowledge_point in knowledge_package.knowledge_points:
        cur_document, rag_candidates_json_list = knowledge_point2embedding(knowledge_point), []
        rel_documents = bge_pipeline.retrieve(cur_document.page_content)
        for rel_document in rel_documents:
            rag_candidates_json = {
                "code": rel_document.metadata.get("code"),
                "name": rel_document.metadata.get("name"),
                "level": rel_document.metadata.get("level"),
                "teaching_for_lecture": rel_document.metadata.get("teaching_for_lecture"),
                "evidence_sentences": rel_document.metadata.get("evidence_sentences"),
            }
            rag_candidates_json_list.append(rag_candidates_json)

        knowledge_network: KnowledgeNetwork = knowledge_network_chain.invoke({
            "textbook_name": subject_context.document.evidence,
            "section_title": subject_context.section_title,
            "one_kp_json": {
                "code": knowledge_point.code,
                "name": knowledge_point.name,
                "level": knowledge_point.level,
                "teaching_for_lecture": knowledge_point.teaching_for_lecture,
                "evidence_sentences": knowledge_point.evidence_sentences
            },
            "rag_candidates_json_list": json.dumps(rag_candidates_json_list),
        })
        print("knowledge_network success: ", json.dumps(knowledge_network.dict()))

    return subject_context


